solution_code:
#include <iostream>
#include <string>
#include <utility>

template <typename T>
using StringPair = std::pair<std::string, T>;

template <typename T>
void printPair(const StringPair<T>& p)
{
    std::cout << p.first << ' ' << p.second << '\n';
}

int main()
{
    std::string word1, word2;
    int intVal{};
    double dblVal{};
    std::cin >> word1 >> intVal >> word2 >> dblVal;

    StringPair<int> a{ word1, intVal };
    StringPair<double> b{ word2, dblVal };

    printPair(a);
    printPair(b);

    return 0;
}

